import { useEffect, useState } from 'react'
import { Zap, Printer, Trash2 } from 'lucide-react'
import { supabase } from '../lib/supabase'
import { useAuth } from '../hooks/useAuth'
import { globalToast } from '../components/Layout'

const logoUrl = '/logo.jpg'
const LOGO_B64 = 'data:image/jpeg;base64,'

const MESES = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre']

const EMISOR = {
  nombre: 'Yeny Rubi Ruiz Carvajal',
  direccion: 'Calle Valdecanillas 59, 3A',
  cp_ciudad: '28037 Madrid',
  nie: 'Z1806715R',
  iban: 'ES9420858284100330219325',
  bizum: '622334126',
  empresa: 'TELEPAN HENARES S.G.L.',
  tel: '633 958 532',
}

const GRUPOS_PAGO = [
  { key: 'TOTAL',         label: '📊 Total General', color: '#E8670A' },
  { key: 'Efectivo',      label: '💵 Efectivo',       color: '#16a34a' },
  { key: 'Transferencia', label: '🏦 Transferencia',  color: '#2563eb' },
  { key: 'Bizum',         label: '📱 Bizum',           color: '#7c3aed' },
  { key: 'Domiciliación', label: '🔄 Domiciliación',  color: '#ca8a04' },
]

function buildHTML(factura: any, lineas: any[]) {
  const c = factura.clientes
  const mesLabel = MESES[parseInt(factura.mes?.split('-')[1] || '1') - 1]
  const anio = factura.mes?.split('-')[0]

  const filas = (lineas || []).map((l: any) => {
    const base = Number(l.cantidad) * Number(l.precio)
    const iva = l.iva || 4
    const total = base * (1 + iva / 100)
    return `<tr>
      <td><strong>${l.producto_nombre}</strong></td>
      <td style="text-align:center">${l.cantidad}</td>
      <td style="text-align:right">${Number(l.precio).toFixed(2)} €</td>
      <td style="text-align:center;color:${iva<=4?'#16a34a':iva<=10?'#E8670A':'#dc2626'};font-weight:800">${iva}%</td>
      <td style="text-align:right;font-weight:800">${total.toFixed(2)} €</td>
    </tr>`
  }).join('')

  return `<!DOCTYPE html><html><head><meta charset="UTF-8">
<title>Factura ${factura.numero}</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&display=swap');
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:'Nunito',Arial,sans-serif;padding:28px 32px;max-width:820px;margin:0 auto;color:#1a1a1a;font-size:12.5px}
.header{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:4px solid #E8670A;padding-bottom:14px;margin-bottom:16px}
.logo{width:170px;object-fit:contain}
.emisor{font-size:0.78rem;color:#555;margin-top:6px;line-height:1.7}
.emisor strong{color:#5a2d0c}
.factura-title{text-align:right}
.factura-title h1{font-size:1.5rem;font-weight:900;color:#E8670A;margin-bottom:6px}
.factura-num{font-size:1.05rem;font-weight:900;color:#5a2d0c;background:#fff8f0;border:2px solid #E8670A;border-radius:8px;padding:4px 14px;display:inline-block;margin-bottom:6px}
.factura-fecha{font-size:0.8rem;color:#888}
.datos-grid{display:grid;grid-template-columns:1.4fr 1fr;gap:12px;margin-bottom:16px}
.box{background:#fff8f0;border:1.5px solid #f5e8d8;border-radius:10px;padding:11px 14px}
.box-title{font-size:0.62rem;text-transform:uppercase;letter-spacing:0.08em;color:#E8670A;font-weight:900;display:block;margin-bottom:5px;border-bottom:1px solid #f5e8d8;padding-bottom:4px}
.box strong{font-size:0.9rem}
.box .sub{font-size:0.75rem;color:#777;margin-top:3px;line-height:1.6}
table{width:100%;border-collapse:collapse;margin-bottom:14px;font-size:0.82rem}
thead th{background:#E8670A;color:white;padding:7px 9px;text-align:left;font-size:0.7rem;text-transform:uppercase;font-weight:800}
tbody td{padding:6px 9px;border-bottom:1px solid #f5e0c5;vertical-align:middle}
tbody tr:nth-child(even){background:#fffaf6}
.total-box{display:flex;justify-content:flex-end;margin-bottom:14px}
.total-inner{background:#E8670A;color:white;font-size:1.4rem;font-weight:900;padding:12px 20px;border-radius:10px;display:flex;gap:16px;align-items:center}
.total-inner span:first-child{font-size:0.75rem;opacity:0.85;font-weight:700}
.pago{display:flex;gap:18px;background:#f9fafb;border:1.5px solid #e5e7eb;border-radius:10px;padding:11px 14px;font-size:0.78rem;margin-bottom:12px;flex-wrap:wrap}
.pago-lbl{font-size:0.62rem;color:#aaa;text-transform:uppercase;font-weight:800;display:block;margin-bottom:2px}
.pago-val{font-weight:800;color:#1a1a1a}
@media print{body{padding:16px 20px}}
</style></head><body>

<div class="header">
  <div>
    <img src="${LOGO_B64}" class="logo" alt="TelePan Henares"/>
    <div class="emisor">
      <strong>${EMISOR.empresa}</strong><br>
      ${EMISOR.nombre} · NIE: ${EMISOR.nie}<br>
      ${EMISOR.direccion} · ${EMISOR.cp_ciudad}
    </div>
  </div>
  <div class="factura-title">
    <h1>FACTURA DE VENTA</h1>
    <div class="factura-num">${factura.numero}</div><br>
    <div class="factura-fecha">Fecha: <strong>${factura.fecha}</strong></div>
    <div class="factura-fecha">Periodo: <strong>${mesLabel} ${anio}</strong></div>
  </div>
</div>

<div class="datos-grid">
  <div class="box">
    <span class="box-title">📋 Datos del cliente</span>
    <strong>${c?.nombre || ''}</strong>
    <div class="sub">
      ${c?.direccion || ''}<br>
      ${c?.codigo_postal || ''} ${c?.poblacion || ''}
    </div>
  </div>
  <div class="box">
    <span class="box-title">🧾 Datos de factura</span>
    <div style="font-size:0.82rem;display:flex;flex-direction:column;gap:4px">
      <div><strong>Nº Factura:</strong> ${factura.numero}</div>
      <div><strong>Mes:</strong> ${mesLabel} ${anio}</div>
    </div>
  </div>
</div>

<table>
  <thead>
    <tr>
      <th style="width:36%">Producto</th>
      <th style="width:10%;text-align:center">Cant.</th>
      <th style="width:14%;text-align:right">Precio s/IVA</th>
      <th style="width:10%;text-align:center">IVA</th>
      <th style="width:15%;text-align:right">Total c/IVA</th>
    </tr>
  </thead>
  <tbody>${filas}</tbody>
</table>

<div class="total-box">
  <div class="total-inner">
    <span>TOTAL A PAGAR</span>
    <span>${Number(factura.total).toFixed(2)} €</span>
  </div>
</div>

<div class="pago">
  <div>
    <span class="pago-lbl">🏦 IBAN (Transferencia)</span>
    <span class="pago-val">${EMISOR.iban}</span>
  </div>
  <div>
    <span class="pago-lbl">📱 Bizum</span>
    <span class="pago-val">${EMISOR.bizum}</span>
  </div>
  <div>
    <span class="pago-lbl">💳 Forma de pago</span>
    <span class="pago-val">${factura.tipo_pago}</span>
  </div>
</div>

<script>window.onload=()=>window.print()</script>
</body></html>`
}

export default function Facturas() {
  const { user } = useAuth()
  const now = new Date()
  const [mes, setMes] = useState(String(now.getMonth()))
  const anio = String(now.getFullYear())
  const [facturas, setFacturas] = useState<any[]>([])
  const [loading, setLoading] = useState(false)
  const [tab, setTab] = useState('TOTAL')

  const mesNum = String(parseInt(mes) + 1).padStart(2, '0')

  const load = async () => {
    const { data } = await supabase.from('facturas')
      .select('*, clientes(nombre, direccion, codigo_postal, poblacion, forma_pago)')
      .eq('mes', `${anio}-${mesNum}`).order('numero')
    if (data) setFacturas(data)
  }
  useEffect(() => { load() }, [mes])

  const generarFacturas = async () => {
    if (!user) return
    if (!confirm(`¿Generar facturas para ${MESES[parseInt(mes)]} ${anio}?\nSe eliminarán las ya existentes de ese mes.`)) return
    setLoading(true)
    try {
      const { data: pedidos } = await supabase.from('pedidos')
        .select('*, clientes(nombre, forma_pago), productos(nombre)')
        .gte('fecha', `${anio}-${mesNum}-01`).lte('fecha', `${anio}-${mesNum}-31`).eq('user_id', user.id)
      if (!pedidos?.length) { globalToast('No hay pedidos para este mes', 'info'); setLoading(false); return }

      const { data: existing } = await supabase.from('facturas').select('id').eq('mes', `${anio}-${mesNum}`).eq('user_id', user.id)
      if (existing?.length) {
        for (const f of existing) await supabase.from('lineas_factura').delete().eq('factura_id', f.id)
        await supabase.from('facturas').delete().eq('mes', `${anio}-${mesNum}`).eq('user_id', user.id)
      }

      const byClient: Record<string, any[]> = {}
      pedidos.forEach(p => { if (!byClient[p.cliente_id]) byClient[p.cliente_id]=[]; byClient[p.cliente_id].push(p) })

      const { data: config } = await supabase.from('configuracion').select('num_inicio_facturas').single()
      let num = config?.num_inicio_facturas || 1

      for (const [clienteId, items] of Object.entries(byClient)) {
        const b4 = items.filter(p=>Number(p.iva)<=4).reduce((s,p)=>s+Number(p.cantidad)*Number(p.precio),0)
        const b10 = items.filter(p=>Number(p.iva)>4&&Number(p.iva)<=10).reduce((s,p)=>s+Number(p.cantidad)*Number(p.precio),0)
        const b21 = items.filter(p=>Number(p.iva)>10).reduce((s,p)=>s+Number(p.cantidad)*Number(p.precio),0)
        const c4=b4*.04, c10=b10*.10, c21=b21*.21
        const { data: fac } = await supabase.from('facturas').insert({
          user_id: user.id,
          numero: `F${anio}${mesNum}${String(num).padStart(3,'0')}`,
          cliente_id: clienteId,
          fecha: `${anio}-${mesNum}-${String(new Date().getDate()).padStart(2,'0')}`,
          mes: `${anio}-${mesNum}`,
          tipo_pago: items[0]?.clientes?.forma_pago||'Efectivo',
          base: b4+b10+b21, iva_total: c4+c10+c21, total: b4+b10+b21+c4+c10+c21,
          base4:b4, cuota4:c4, base10:b10, cuota10:c10, base21:b21, cuota21:c21,
        }).select().single()
        if (fac) {
          const byP: Record<string,any>={}
          items.forEach(p=>{ const n=p.productos?.nombre||'Prod'; if(!byP[n]) byP[n]={nombre:n,cantidad:0,precio:Number(p.precio),iva:Number(p.iva)}; byP[n].cantidad+=Number(p.cantidad) })
          await supabase.from('lineas_factura').insert(Object.values(byP).map((l:any)=>({factura_id:fac.id,producto_nombre:l.nombre,cantidad:l.cantidad,precio:l.precio,iva:l.iva})))
        }
        num++
      }
      globalToast(`✅ ${Object.keys(byClient).length} facturas generadas`); load()
    } catch(err:any) { globalToast(err.message,'error') }
    setLoading(false)
  }

  const printOne = async (f: any) => {
    const { data: lineas } = await supabase.from('lineas_factura').select('*').eq('factura_id', f.id)
    const w = window.open('','_blank'); if(!w) return
    w.document.write(buildHTML(f, lineas||[])); w.document.close()
  }

  const printGroup = async (list: any[]) => {
    for (const f of list) {
      const { data: lineas } = await supabase.from('lineas_factura').select('*').eq('factura_id', f.id)
      const w = window.open('','_blank'); if(!w) return
      w.document.write(buildHTML(f, lineas||[])); w.document.close()
      await new Promise(r=>setTimeout(r,400))
    }
    globalToast(`📄 ${list.length} facturas abiertas para imprimir`)
  }

  const deleteFactura = async (id: string) => {
    if (!confirm('¿Eliminar esta factura?')) return
    await supabase.from('lineas_factura').delete().eq('factura_id', id)
    await supabase.from('facturas').delete().eq('id', id)
    globalToast('Factura eliminada'); load()
  }

  const filtered = tab === 'TOTAL' ? facturas : facturas.filter(f => (f.tipo_pago||f.clientes?.forma_pago) === tab)
  const totalFiltered = filtered.reduce((s,f)=>s+Number(f.total),0)
  const totalGeneral = facturas.reduce((s,f)=>s+Number(f.total),0)

  return (
    <div>
      <div className="page-header">
        <h1 className="page-title">🧾 Facturas</h1>
        <div className="page-actions">
          <select className="select" style={{width:'auto'}} value={mes} onChange={e=>setMes(e.target.value)}>
            {MESES.map((m,i)=><option key={i} value={String(i)}>{m} {anio}</option>)}
          </select>
          <button className="btn btn-success" onClick={generarFacturas} disabled={loading}>
            <Zap size={16}/> {loading?'Generando...':'Generar facturas'}
          </button>
        </div>
      </div>

      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(140px,1fr))',gap:10,marginBottom:16}}>
        {GRUPOS_PAGO.map(g => {
          const list = g.key==='TOTAL' ? facturas : facturas.filter(f=>(f.tipo_pago||f.clientes?.forma_pago)===g.key)
          const tot = list.reduce((s,f)=>s+Number(f.total),0)
          return (
            <div key={g.key} className="card" onClick={()=>setTab(g.key)} style={{
              padding:'12px 14px', cursor:'pointer',
              border: tab===g.key ? `2px solid ${g.color}` : '1px solid #f5e8d8',
              background: tab===g.key ? g.color+'10' : 'white'
            }}>
              <div style={{fontSize:'0.7rem',fontWeight:800,color:g.color,marginBottom:2}}>{g.label}</div>
              <div style={{fontFamily:'Fredoka One',fontSize:'1.15rem',color:g.color}}>{tot.toFixed(2)} €</div>
              <div style={{fontSize:'0.72rem',color:'var(--gris)'}}>{list.length} facturas</div>
            </div>
          )
        })}
      </div>

      {filtered.length > 0 && (
        <div style={{display:'flex',gap:8,alignItems:'center',marginBottom:12}}>
          <span style={{fontWeight:800,fontSize:'0.875rem',color:'var(--marron)'}}>
            {GRUPOS_PAGO.find(g=>g.key===tab)?.label} — {filtered.length} facturas — {totalFiltered.toFixed(2)} €
          </span>
          <button className="btn btn-secondary btn-sm" onClick={()=>printGroup(filtered)}>
            <Printer size={14}/> Imprimir todo el grupo
          </button>
        </div>
      )}

      <div className="card" style={{padding:0}}>
        <div className="table-wrap">
          <table>
            <thead><tr><th>Nº Factura</th><th>Cliente</th><th>Pago</th><th>Base</th><th>IVA</th><th>Total</th><th></th></tr></thead>
            <tbody>
              {filtered.map(f=>(
                <tr key={f.id}>
                  <td><strong style={{color:'var(--naranja)'}}>{f.numero}</strong></td>
                  <td>{f.clientes?.nombre}</td>
                  <td><span className="badge badge-gray">{f.tipo_pago}</span></td>
                  <td>{Number(f.base).toFixed(2)} €</td>
                  <td>{Number(f.iva_total).toFixed(2)} €</td>
                  <td><strong style={{color:'#16a34a'}}>{Number(f.total).toFixed(2)} €</strong></td>
                  <td>
                    <div style={{display:'flex',gap:4}}>
                      <button className="btn btn-secondary btn-sm" onClick={()=>printOne(f)}><Printer size={13}/> PDF</button>
                      <button className="btn btn-danger btn-sm btn-icon" onClick={()=>deleteFactura(f.id)}><Trash2 size={13}/></button>
                    </div>
                  </td>
                </tr>
              ))}
              {filtered.length===0&&<tr><td colSpan={7}><div className="empty-state"><p>No hay facturas</p><span>Genera los pedidos del mes primero</span></div></td></tr>}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  )
}
